import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"14、节制【XIV】","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/14、节制【XIV】.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/14、节制【XIV】.md"}'),p={name:"4.资源分区/2.改造与功法/改造/4.综合类/替身/阿尔卡纳/14、节制【XIV】.md"};function d(_,a,i,l,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_14、节制【xiv】",tabindex:"-1"},[s("14、节制【XIV】 "),e("a",{class:"header-anchor",href:"#_14、节制【xiv】","aria-label":'Permalink to "14、节制【XIV】"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘")])])],-1),o('<h1 id="节制" tabindex="-1">节制 <a class="header-anchor" href="#节制" aria-label="Permalink to &quot;节制&quot;">​</a></h1><p>黄色节制</p><p>SS+19200<br> 替身外貌：<br> 黄色节制的外形是一团黄色软泥状，类似史莱姆的生物，但是没有五官也没有自我意识，它凭依在替身使者身上，所以一般人也能看见。</p><p>替身数据：<br> 破坏力D<br> 速度C（偏斜防御）<br> 射程E<br> 持续力A<br> 精密动作性E<br> 成长性D</p><p>替身对应主属性：耐力</p><p>替身能力：<br> 近距离力量型：近距离力量型都具有的基础能力，控制替身直接对射程范围内所有目标进行肉搏攻击，检定方式为【决心—专注—主专业：替身使用—副专业：精神力（专注下属副专业）】。<br> 吸收：黄色节制的主要能力是吞食有机物来变得更加强大，每次具现化后每吞噬体积为1的有机物（各种生物、食物等），就能为黄色节制增加1体积与1点替身使用加值，上限为【决心】点，每次收回后再具现会重置这个加成，此外控制黄色节制对目标造成伤害时会附带等量的【侵噬】异常点，强韧豁免，【侵噬】异常点一种基于流血升级而来的第四档异常点，表现为部分黄色软泥附着在目标被攻击部位不断增长吞噬目标身体，具有与流血一样的不良效果，并且每轮目前需要强韧对抗等于自身【侵噬】异常点数，增加未豁免数点的【侵噬】异常点。<br> 外观复制：黄色节制能够透过自身的胶状性质复制他人的外貌，视为B级变形效果。</p><p>橡胶盔甲：除了伪装，黄色节制也可以覆盖替身使者全身的橡胶盔甲，能为本体提供【决心×3】点全伤害吸收，并且当有目标近战攻击黄色节制所覆盖的替身使者时，会被黄色节制自动吞噬一次接触部位的有机物造成【决心上附加成功数】点严重伤害和等量的【侵噬】异常点。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const V=r(p,[["render",d]]);export{f as __pageData,V as default};
